mapper.select:
SELECT s.id, s.name, s.email, s.phone, s.status, s.referral_source_id, rs.name AS referral_source_name, STRING_AGG(DISTINCT c.name, ', ' ORDER BY c.name) FILTER (WHERE c.id IS NOT NULL) AS course_names, EXISTS( SELECT 1 FROM payments p2 WHERE p2.student_id = s.id AND p2.status = 'UNPAID' ) AS has_unpaid, s.created_at, s.updated_at FROM students s INNER JOIN referral_sources rs ON s.referral_source_id = rs.id LEFT JOIN enrollments e ON e.student_id = s.id LEFT JOIN courses c ON e.course_id = c.id
AND ( s.name ILIKE CONCAT('%', #{escapedKeyword}, '%') ESCAPE '\' OR s.email ILIKE CONCAT('%', #{escapedKeyword}, '%') ESCAPE '\' OR COALESCE(s.phone, '') ILIKE CONCAT('%', #{escapedKeyword}, '%') ESCAPE '\' )
AND s.status = #{status}
AND s.referral_source_id = #{referralSourceId}
AND EXISTS( SELECT 1 FROM payments p3 WHERE p3.student_id = s.id AND p3.status = 'UNPAID' ) = #{hasUnpaid}
AND EXISTS( SELECT 1 FROM enrollments e2 WHERE e2.student_id = s.id AND e2.course_id = #{courseId} )
AND EXISTS( SELECT 1 FROM enrollments e3 INNER JOIN courses c3 ON e3.course_id = c3.id WHERE e3.student_id = s.id AND c3.instructor_id = #{instructorId} )
GROUP BY s.id, rs.name ORDER BY s.created_at DESC, s.id DESC

SELECT
FROM students s INNER JOIN referral_sources rs ON s.referral_source_id = rs.id WHERE s.id = #{id}
AND EXISTS( SELECT 1 FROM enrollments e INNER JOIN courses c ON e.course_id = c.id WHERE e.student_id = s.id AND c.instructor_id = #{instructorId} )

mapper.update:
UPDATE students
SET status = #{status}
WHERE id = #{id}

mapper.select:
SELECT EXISTS(
    SELECT 1
    FROM students
    WHERE email = #{email}
      AND id != #{id}
)
